--- a/src/InMemory/InMemoryFilesystemAdapter.php
+++ b/src/InMemory/InMemoryFilesystemAdapter.php
@@ -99,6 +99,14 @@ class InMemoryFilesystemAdapter implements FilesystemAdapter
     public function createDirectory(string $path, Config $config): void
     {
         $filePath = rtrim($path, '/') . '/' . self::DUMMY_FILE_FOR_FORCED_LISTING_IN_FLYSYSTEM_TEST;
+
+        if ($config->get(Config::OPTION_VISIBILITY) === null) {
+            $directoryVisibility = $config->get(Config::OPTION_DIRECTORY_VISIBILITY);
+            if ($directoryVisibility !== null) {
+                $config = $config->withSetting(Config::OPTION_VISIBILITY, $directoryVisibility);
+            }
+        }
+
         $this->write($filePath, '', $config);
     }
